           <section className="bg-gradient-to-br from-hot-pink via-lime to-aqua rounded-[2.5rem] p-10 shadow-2xl relative overflow-hidden group">
              <div className="absolute top-0 right-0 p-8 opacity-10 group-hover:rotate-12 transition-transform duration-700">
                 <Zap size={120} strokeWidth={3} className="text-black" />
