                    <div className="mt-6 flex gap-3">
                       <span className="bg-black/90 text-white px-4 py-1.5 rounded-full text-[9px] font-black tracking-widest border border-white/10">TOTAL LOTE: ${currentResults.precioTotal.toLocaleString()}</span>
                    </div>
                 </div>
                 <div className="bg-black/10 backdrop-blur-2xl p-6 rounded-[2rem] border border-white/10">
                    <h4 className="text-black/60 font-black text-[9px] uppercase tracking-widest mb-4">Métrica de Negocio</h4>
                    <div className="space-y-3">
                       <div className="flex justify-between items-center text-xs font-bold">
                          <span className="text-black/40 uppercase tracking-widest text-[10px]">Costo Producción</span>
                          <span className="text-black font-black">${currentResults.costoTotal.toLocaleString()}</span>
                       </div>
                       <div className="pt-4 border-t border-black/10 flex justify-between items-center">
                          <span className="text-black font-black text-[10px] uppercase tracking-widest">Margen</span>
