                 >
                    <Download size={16} /> EXPORTAR PDF CLIENTE
                 </button>
              </div>

              {quoteItems.length === 0 ? (
                <div className="py-16 text-center border-2 border-dashed border-white/5 rounded-[2rem]">
                   <p className="text-white/20 font-black uppercase tracking-widest text-[10px]">Lista vacía. Agrega prendas para cotizar.</p>
                </div>
              ) : (
                <div className="space-y-4">
                  {quoteItems.map(item => (
                    <div key={item.id} className="bg-white/5 border border-white/5 p-6 rounded-[1.5rem] flex flex-col sm:flex-row justify-between items-center gap-6 hover:border-aqua/30 transition-all group">
                       <div className="flex items-center gap-6">
