                       </div>
                    </div>
                  ))}

                  <div className="mt-8 pt-8 border-t border-white/10 flex justify-between items-end">
                     <div>
                        <p className="text-hot-pink font-black text-[10px] uppercase tracking-[0.3em] mb-2 flex items-center gap-2">
                           <Target size={12} /> GRAN TOTAL
                        </p>
                        <p className="text-5xl font-black text-white tracking-tighter">${quoteItems.reduce((a, b) => a + b.results.precioTotal, 0).toLocaleString()}</p>
                     </div>
                  </div>
                </div>
              )}
           </section>

           {/* AI Assistant Section */}
           <section className="card p-10 relative overflow-hidden">
              <div className="absolute top-0 right-0 w-32 h-32 bg-sun/5 rounded-full -mr-16 -mt-16 blur-3xl"></div>
              <div className="flex items-center justify-between mb-8">
                 <div className="flex items-center gap-4">
                    <Sparkles className="text-sun" size={24} />
                    <div>
                       <h4 className="text-white font-black uppercase text-md tracking-widest italic">IA Assistant</h4>
                       <p className="text-[8px] text-sun font-black uppercase tracking-[0.2em]">PITCH DE VENTAS</p>
                    </div>
                 </div>
                 <button onClick={generatePitch} disabled={isAiLoading} className="btn-primary px-8 py-3.5 text-[10px] tracking-widest uppercase shadow-xl disabled:opacity-50">
                    {isAiLoading ? <Loader2 className="animate-spin" size={16} /> : 'GENERAR ARGUMENTO'}
                 </button>
              </div>

              <div className="min-h-[140px] bg-black/40 rounded-[1.5rem] p-8 border border-white/5 text-white/90 leading-relaxed font-medium italic text-lg shadow-inner">
                 {aiAdvice ? `"${aiAdvice}"` : "Carga una referencia para obtener un discurso rockero brutal para tu cliente."}
              </div>

              <div className="mt-8 pt-8 border-t border-white/10">
                 <label className="flex items-center gap-2 text-[10px] font-black text-muted uppercase tracking-widest mb-4"><MessageSquare size={14} className="text-neon-green" /> Notas para el PDF</label>
                 <textarea 
                  value={observaciones} 
                  onChange={(e) => setObservaciones(e.target.value)} 
                  className="w-full bg-black/40 border border-white/10 rounded-[1.5rem] px-8 py-6 text-white/80 text-xs font-bold min-h-[100px] resize-none focus:ring-1 focus:ring-hot-pink outline-none transition-all" 
                  placeholder="Ej: Entrega en 5 días hábiles, cuidados de lavado..." 
                 />
              </div>
           </section>
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-black/95 backdrop-blur-3xl border-t border-white/5 py-4 px-12 z-[60]">
         <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4 text-[9px] font-black uppercase tracking-[0.4em]">
            <div className="flex gap-10 text-white/20">
               <span className="flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-hot-pink"></div> DTG / DTF EXPERTS</span>
               <span className="flex items-center gap-2"><div className="w-2 h-2 rounded-full bg-neon-green"></div> PREMIUM FABRICS</span>
            </div>
            <div className="text-aqua italic tracking-[0.8em] animate-pulse">FURIA ROCK • COCO YEMA</div>
         </div>
      </footer>
    </div>
  );
};

export default App;

