                <div className="space-y-4">
                  {quoteItems.map(item => (
                    <div key={item.id} className="bg-white/5 border border-white/5 p-6 rounded-[1.5rem] flex flex-col sm:flex-row justify-between items-center gap-6 hover:border-aqua/30 transition-all group">
