              <div className="min-h-[140px] bg-black/40 rounded-[1.5rem] p-8 border border-white/5 text-white/90 leading-relaxed font-medium italic text-lg shadow-inner">
                 {aiAdvice ? `"${aiAdvice}"` : "Carga una referencia para obtener un discurso rockero brutal para tu cliente."}
