              <div className="mt-8 pt-8 border-t border-white/10">
                 <label className="flex items-center gap-2 text-[10px] font-black text-muted uppercase tracking-widest mb-4"><MessageSquare size={14} className="text-neon-green" /> Notas para el PDF</label>
                 <textarea 
