                  className="w-full bg-black/40 border border-white/10 rounded-[1.5rem] px-8 py-6 text-white/80 text-xs font-bold min-h-[100px] resize-none focus:ring-1 focus:ring-hot-pink outline-none transition-all" 
                  placeholder="Ej: Entrega en 5 días hábiles, cuidados de lavado..." 
                 />
              </div>
           </section>
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-black/95 backdrop-blur-3xl border-t border-white/5 py-4 px-12 z-[60]">
         <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4 text-[9px] font-black uppercase tracking-[0.4em]">
            <div className="flex gap-10 text-white/20">
