      <header className="max-w-7xl mx-auto mb-12">
        <div className="app-header">
          <div className="flex items-center gap-6 z-10">
            <img src={LOGO_FURIA} className="logo-img" alt="Furia" />
            <div>
              <h1 className="text-3xl font-black italic tracking-tighter uppercase splatter-pink">FURIA ROCK</h1>
              <p className="text-[10px] text-muted font-bold tracking-[0.4em] uppercase">Cotizador • DTG / DTF</p>
            </div>
          </div>

          <div className="hidden md:flex flex-col items-center gap-2 z-10 mx-4">
