                             </div>
                          </div>
                       </div>
                       <div className="flex items-center gap-8">
                          <div className="text-right">
                             <p className="text-[9px] text-slate-500 font-black uppercase tracking-widest mb-1">Subtotal Item</p>
                             <p className="text-white font-black text-2xl tracking-tighter">${item.results.precioTotal.toLocaleString()}</p>
                          </div>
                          <button onClick={() => removeItem(item.id)} className="p-4 bg-slate-900 hover:bg-red-500/20 text-slate-600 hover:text-red-500 rounded-2xl transition-all border border-slate-700">
                             <Trash2 size={18} />
                          </button>
                       </div>
                    </div>
                  ))}

                  <div className="mt-12 pt-10 border-t border-slate-800 flex justify-between items-end">
                     <div className="space-y-2">
                        <p className="text-hot-pink font-black text-[10px] uppercase tracking-[0.4em] flex items-center gap-2">
                           <Target size={14} /> VALOR TOTAL DEL PEDIDO
                        </p>
                        <p className="text-6xl font-black text-white tracking-tighter">${quoteItems.reduce((a, b) => a + b.results.precioTotal, 0).toLocaleString()}</p>
                     </div>
                  </div>
                </div>
              )}
           </section>

           {/* IA SALES ASSISTANT */}
           <section className="card p-10 relative overflow-hidden bg-slate-900/40">
              <div className="flex items-center justify-between mb-10">
                 <div className="flex items-center gap-5">
                    <div className="bg-sun/10 p-3 rounded-2xl"><Sparkles className="text-sun" size={26} /></div>
                    <div>
                       <h4 className="text-white font-black uppercase text-lg tracking-widest italic">IA Sales Pitch</h4>
                       <p className="text-[9px] text-sun font-black uppercase tracking-widest">Generador de Argumentos de Venta</p>
                    </div>
                 </div>
                 <button onClick={generatePitch} disabled={isAiLoading} className="btn-primary px-10 py-4 text-[10px] tracking-widest uppercase shadow-xl disabled:opacity-50 flex items-center gap-3">
                    {isAiLoading ? <Loader2 className="animate-spin" size={16} /> : <Zap size={16} />} GENERAR DISCURSO
                 </button>
              </div>

              <div className="min-h-[160px] bg-slate-950/50 rounded-[2rem] p-10 border border-slate-800 text-slate-300 leading-relaxed font-medium italic text-lg shadow-inner relative group">
                 <div className="absolute top-4 left-4 text-slate-800"><MessageSquare size={40} /></div>
                 <div className="relative z-10">
                    {aiAdvice ? `"${aiAdvice}"` : "Configura un producto y pulsa 'Generar Discurso' para obtener un argumento de venta con actitud rockera."}
                 </div>
              </div>

              <div className="mt-12 space-y-4">
                 <label className="flex items-center gap-3 text-[10px] font-black text-slate-400 uppercase tracking-widest px-1"><MessageSquare size={14} className="text-neon-green" /> Observaciones para la cotización PDF</label>
                 <textarea 
                  value={observaciones} 
                  onChange={(e) => setObservaciones(e.target.value)} 
                  className="w-full bg-slate-900 border border-slate-700 rounded-[1.8rem] px-8 py-6 text-white text-sm font-medium min-h-[120px] resize-none focus:ring-2 focus:ring-hot-pink outline-none transition-all" 
                  placeholder="Ej: Entrega en Bogotá 3 días hábiles. Garantía de estampado por 6 meses..." 
                 />
              </div>
           </section>
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-slate-950/90 backdrop-blur-3xl border-t border-white/5 py-5 px-12 z-[60]">
         <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-6 text-[9px] font-black uppercase tracking-[0.5em] text-slate-500">
            <div className="flex gap-12">
               <span className="flex items-center gap-3"><div className="w-2.5 h-2.5 rounded-full bg-hot-pink shadow-[0_0_10px_#FF4FD8]"></div> PREMIUM DTG</span>
               <span className="flex items-center gap-3"><div className="w-2.5 h-2.5 rounded-full bg-neon-green shadow-[0_0_10px_#34FF4A]"></div> 100% ALGODÓN</span>
            </div>
            <div className="text-aqua italic tracking-[0.8em] flex items-center gap-4">
               FURIA ROCK <div className="w-1 h-1 bg-slate-800 rounded-full"></div> COCO YEMA
            </div>
         </div>
      </footer>
    </div>
  );
};

export default App;

