Asegura que el botón tenga un ID fijo

En tu HTML, ponle esto al botón:

<button id="btnExportPDF" type="button">EXPORTAR COTIZACIÓN PDF</button>


(Si ya lo tiene, perfecto. Si no, cámbialo a ese ID.)

✅ 2) Asegura que la librería exista (pon este script)

En tu HTML (antes de tu JS principal):

<script src="https://cdn.jsdelivr.net/npm/html2pdf.js@0.10.1/dist/html2pdf.bundle.min.js"></script>

✅ 3) Listener que NO se pierde aunque se vuelva a pintar la UI

Pega esto en tu JS una sola vez:

document.addEventListener("click", (e) => {
  const btn = e.target.closest("#btnExportPDF");
  if (!btn) return;

  // 1) Valida librería
  if (typeof html2pdf === "undefined") {
    alert("No se cargó la librería html2pdf. Revisa el <script> del CDN.");
    return;
  }

  // 2) Valida items
  if (!window.itemsCotizacion || window.itemsCotizacion.length === 0) {
    alert("No hay productos en el pedido para exportar.");
    return;
  }

  // 3) Genera PDF
  generarPDFCliente();
});

✅ 4) Función robusta generarPDFCliente() (copia y pega)

Esto genera el PDF con tu tabla y no muestra planchado/empaque, y además discrimina colores (Camiseta/Bermuda):

function fmtCOP(n){
  return "$" + Math.round(Number(n||0)).toLocaleString("es-CO");
}

function generarPDFCliente(){
  const pdfContainer = document.getElementById("pdfContainer")
    || (() => {
      const d = document.createElement("div");
      d.id = "pdfContainer";
      d.style.position = "absolute";
      d.style.left = "-9999px";
      d.style.top = "-9999px";
      document.body.appendChild(d);
      return d;
    })();

  const rows = window.itemsCotizacion.map(it => `
    <tr>
      <td style="padding:10px;border-bottom:1px solid #ddd;">${it.referencia}</td>
      <td style="padding:10px;border-bottom:1px solid #ddd;">
        Talla: ${it.talla}<br>
        ${it.colorCamiseta ? `<strong>Camiseta:</strong> ${it.colorCamiseta}<br>` : ``}
        ${it.colorBermuda ? `<strong>Bermuda/Jogger:</strong> ${it.colorBermuda}` : ``}
      </td>
      <td style="padding:10px;border-bottom:1px solid #ddd;text-align:center;">${it.cantidad}</td>
      <td style="padding:10px;border-bottom:1px solid #ddd;text-align:right;">${fmtCOP(it.unit)}</td>
      <td style="padding:10px;border-bottom:1px solid #ddd;text-align:right;">${fmtCOP(it.total)}</td>
    </tr>
  `).join("");

  const totalGeneral = window.itemsCotizacion.reduce((a,b)=>a+Number(b.total||0),0);

  pdfContainer.innerHTML = `
    <div style="font-family:Arial;padding:16px;">
      <h2 style="margin:0 0 8px;">Cotización - Furia Rock / Coco Yema</h2>
      <div style="font-size:12px;margin-bottom:10px;">Fecha: ${new Date().toLocaleDateString("es-CO")}</div>

      <table style="width:100%;border-collapse:collapse;font-size:12px;">
        <thead>
          <tr>
            <th style="padding:10px;border-bottom:2px solid #ff6a00;text-align:left;">Referencia</th>
            <th style="padding:10px;border-bottom:2px solid #ff6a00;text-align:left;">Detalle / Talla</th>
            <th style="padding:10px;border-bottom:2px solid #ff6a00;text-align:center;">Cant.</th>
            <th style="padding:10px;border-bottom:2px solid #ff6a00;text-align:right;">V. Unit</th>
            <th style="padding:10px;border-bottom:2px solid #ff6a00;text-align:right;">V. Total</th>
          </tr>
        </thead>
        <tbody>${rows}</tbody>
      </table>

      <div style="margin-top:12px;text-align:right;font-size:14px;">
        <strong>Total Cotizado: ${fmtCOP(totalGeneral)}</strong>
      </div>
    </div>
  `;

  const opt = {
    margin: 10,
    filename: `cotizacion_${Date.now()}.pdf`,
    image: { type: "jpeg", quality: 0.98 },
    html2canvas: { scale: 2, useCORS: true },
    jsPDF: { unit: "mm", format: "a4", orientation: "portrait" }
  };

  html2pdf().set(opt).from(pdfContainer).save();
}

✅ 5) CLAVE: expón tu lista de items al “window”

Si tu variable está como let itemsCotizacion = [], agrega:

window.itemsCotizacion = itemsCotizacion;


y cada vez que agregues/quites items, actualiza:

window.itemsCotizacion = itemsCotizacion;

