              <button onClick={addToQuote} className="btn-primary w-full py-5 text-[11px] font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 shadow-xl mt-4">
                <Plus size={18} /> AGREGAR AL PEDIDO
