    talla: TALLAS_NINO[3],
    colorCamiseta: COLORES_CAMISETA[1], // Negro
    colorBermuda: COLORES_BERMUDA[1], // Negro
    cmEstampado: 0,
    cmCorazon: 0,
    qtyPlanchado: 1,
    costoEmpaque: COSTO_EMPAQUE
  });
  const [observaciones, setObservaciones] = useState("");
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    try {
      const data = await file.arrayBuffer();
      const wb = XLSX.read(data, { type: 'array' });
      const ws = wb.Sheets[wb.SheetNames[0]];
      const rows = XLSX.utils.sheet_to_json(ws, { defval: "" }) as any[];

      if (!rows.length) return;

      const norm = (s: any) => String(s || "").trim().toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "").replace(/\s+/g, "_");
      const findKey = (obj: any, posibles: string[]) => {
        const keys = Object.keys(obj);
        for (const p of posibles) {
          const hit = keys.find(k => norm(k) === norm(p));
          if (hit) return hit;
        }
        return null;
      };

      const refKey = findKey(rows[0], ["referencia", "ref", "nombre"]);
      const precioKey = findKey(rows[0], ["precio_unitario", "precio", "costo"]);

      if (refKey && precioKey) {
        const newRefs: ProductReference[] = rows.map((row, idx) => ({
          id: String(row[refKey] || `id-${idx}`),
          name: String(row[refKey]),
          baseCost: Number(String(row[precioKey]).replace(/[^\d.]/g, "")) || 0
        })).filter(p => p.name);
        setProductRefs(newRefs);
        setInputs(prev => ({ ...prev, referencia: newRefs[0].id }));
      }
    } catch (err) { alert('Error al procesar el Excel.'); }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  useEffect(() => {
    setInputs(prev => ({
      ...prev,
      talla: prev.categoria === 'Niño' ? TALLAS_NINO[0] : TALLAS_ADULTO[0]
    }));
  }, [inputs.categoria]);

  const currentProduct = useMemo(() => 
    productRefs.find(p => p.id === inputs.referencia) || productRefs[0], 
  [inputs.referencia, productRefs]);

  const currentResults = useMemo((): QuoteResults => {
    const base = currentProduct.baseCost;
    const estampadoPrincipal = (Number(inputs.cmEstampado) || 0) * COSTO_CM2;
    const estampadoCorazon = (Number(inputs.cmCorazon) || 0) * COSTO_CM2;
    const costoPlanchado = (Number(inputs.qtyPlanchado) || 0) * COSTO_PLANCHADO;
    const empaque = Number(inputs.costoEmpaque) || 0;

    const costoTotalUnidad = base + estampadoPrincipal + estampadoCorazon + costoPlanchado + empaque;

    // REGLA DE NEGOCIO: Niño = 35k, Adulto = 30k
    const ganancia = inputs.categoria === 'Niño' ? GANANCIA_NINO : GANANCIA_ADULTO;
    const precioUnidad = Math.round(costoTotalUnidad + ganancia);

    return {
      costoBase: base,
      costoEstampado: estampadoPrincipal,
      costoCorazon: estampadoCorazon,
      costoPlanchado: costoPlanchado,
      costoEmpaque: empaque,
      costoTotal: costoTotalUnidad,
      precioUnidad,
      precioTotal: precioUnidad * inputs.quantity,
      ganancia,
      margen: (ganancia / precioUnidad) * 100
    };
  }, [inputs, currentProduct]);

  const addToQuote = () => {
    const newItem: QuoteItem = {
      id: crypto.randomUUID(),
      product: currentProduct,
      categoria: inputs.categoria,
      talla: inputs.talla,
      colorCamiseta: inputs.colorCamiseta,
      colorBermuda: inputs.colorBermuda,
      cmEstampado: inputs.cmEstampado,
      cmCorazon: inputs.cmCorazon,
      qtyPlanchado: inputs.qtyPlanchado,
      costoEmpaque: inputs.costoEmpaque,
      quantity: inputs.quantity,
      results: { ...currentResults }
    };
    setQuoteItems(prev => [...prev, newItem]);
  };

  const removeItem = (id: string) => setQuoteItems(prev => prev.filter(it => it.id !== id));

  const formatCOP = (val: number) => `$ ${Math.round(val).toLocaleString('es-CO')}`;

  const downloadPDF = async () => {
    const pdfContainer = document.getElementById("pdf-export-container");
    if (!pdfContainer) return;

    const itemsToExport = quoteItems.length > 0 ? quoteItems : [{
      product: currentProduct,
      categoria: inputs.categoria,
      talla: inputs.talla,
      colorCamiseta: inputs.colorCamiseta,
      colorBermuda: inputs.colorBermuda,
      quantity: inputs.quantity,
      results: currentResults
    }];

    const totalGeneral = itemsToExport.reduce((acc, it) => acc + (it.results?.precioTotal || 0), 0);

    const rowsHtml = itemsToExport.map(it => `
      <tr>
        <td style="padding:10px; border-bottom:1px solid #ddd; font-weight:700; text-align:left;">
          ${it.product.name.toUpperCase()}
        </td>
        <td style="padding:10px; border-bottom:1px solid #ddd; text-align:left; font-size:11px;">
          Talla: ${it.talla}<br>
          ${it.colorCamiseta ? `CAMISETA: <strong>${it.colorCamiseta}</strong><br>` : ``}
          ${it.colorBermuda ? `BERMUDA/JOGGER: <strong>${it.colorBermuda}</strong>` : ``}
        </td>
        <td style="padding:10px; border-bottom:1px solid #ddd; text-align:center;">
          ${it.quantity}
        </td>
        <td style="padding:10px; border-bottom:1px solid #ddd; text-align:right;">
          ${formatCOP(it.results.precioUnidad)}
        </td>
        <td style="padding:10px; border-bottom:1px solid #ddd; text-align:right; font-weight:700;">
          ${formatCOP(it.results.precioTotal)}
        </td>
      </tr>
    `).join('');

    pdfContainer.innerHTML = `
      <div style="font-family: Arial, sans-serif; padding: 40px; color: #000; background: white;">
        <div style="display: flex; justify-content: space-between; align-items: center; border-bottom: 2px solid #FF4FD8; padding-bottom: 20px; margin-bottom: 30px;">
          <div>
            <h1 style="margin: 0; color: #FF4FD8; font-size: 26px; font-weight: 900; letter-spacing: -1px;">FURIA ROCK KIDS</h1>
            <p style="margin: 4px 0 0; color: #666; font-size: 10px; text-transform: uppercase; font-weight: 700; letter-spacing: 2px;">Coco Yema - Premium Fashion</p>
          </div>
          <div style="text-align: right;">
            <p style="margin: 0; font-size: 12px; font-weight: 700;">COTIZACIÓN COMERCIAL</p>
            <p style="margin: 4px 0 0; font-size: 11px; color: #999;">${new Date().toLocaleDateString('es-CO')}</p>
          </div>
        </div>

        <div style="margin-bottom: 25px; font-size: 13px;">
          <p><strong>CLIENTE:</strong> ${inputs.clientName.toUpperCase() || 'VALIOSO CLIENTE'}</p>
        </div>

        <table style="width: 100%; border-collapse: collapse; margin-bottom: 25px;">
          <thead>
            <tr>
              <th style="background:#000; color:#fff; padding:10px; text-align:left; font-size:11px;">REFERENCIA</th>
              <th style="background:#000; color:#fff; padding:10px; text-align:left; font-size:11px;">DETALLES / COLORES</th>
              <th style="background:#000; color:#fff; padding:10px; text-align:center; font-size:11px;">CANT.</th>
              <th style="background:#000; color:#fff; padding:10px; text-align:right; font-size:11px;">V. UNITARIO</th>
              <th style="background:#000; color:#fff; padding:10px; text-align:right; font-size:11px;">V. TOTAL</th>
            </tr>
          </thead>
          <tbody>
            ${rowsHtml}
          </tbody>
        </table>

        <div style="margin-top:14px; text-align:right; font-size:16px; font-weight:900; color:#000;">
          TOTAL: ${formatCOP(totalGeneral)} COP
        </div>

        ${observaciones ? `
          <div style="margin-top: 30px; padding: 15px; background: #fafafa; border: 1px solid #eee; border-radius: 8px; font-size: 11px; color: #444;">
            <p style="margin: 0 0 8px; font-weight: 700; color: #000; text-transform: uppercase;">Observaciones:</p>
            <p style="margin: 0; line-height: 1.5;">${observaciones}</p>
          </div>
        ` : ''}

        <div style="margin-top: 40px; text-align: center; border-top: 1px solid #eee; padding-top: 15px; font-size: 9px; color: #999;">
          <p>Esta cotización tiene una validez de 5 días hábiles. Gracias por confiar en el estilo Furia Rock.</p>
        </div>
      </div>
    `;

    const opt = {
      margin: 10,
      filename: `Cotizacion_FuriaRock_${inputs.clientName || 'Cliente'}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };

    // @ts-ignore
    window.html2pdf().set(opt).from(pdfContainer).save();
  };

