PDF en blanco: haz que SIEMPRE genere con contenido (y que puedas “ver” el HTML antes de descargar)

El PDF en blanco casi siempre pasa por una de estas razones:

rows está vacío (no hay items) o no estás usando itemsCotizacion correcto.

El contenedor del PDF está display:none / con ancho 0 / no alcanza a renderizar antes de save().

Estás generando el PDF desde un nodo que no está en el DOM.

✅ Fix definitivo: crea un contenedor “preview” visible (opcional) + offscreen para el PDF

Pega esto:

function buildPDFHtml({ clienteNombre, fechaStr, rowsHtml, totalGeneral, observaciones }) {
  return `
  <div style="font-family: Arial; padding:18px; color:#000; background:#fff; width: 780px;">
    <div style="display:flex; justify-content:space-between; align-items:flex-start; margin-bottom:12px;">
      <div>
        <div style="font-size:13px;"><strong>CLIENTE:</strong> ${clienteNombre || "CLIENTE VALIOSO"}</div>
        <div style="font-size:12px; margin-top:4px;"><strong>FECHA:</strong> ${fechaStr}</div>
      </div>
    </div>

    <table style="width:100%; border-collapse:collapse; font-size:12px;">
      <thead>
        <tr>
          <th style="background:#000; color:#fff; padding:10px; text-align:left;">REFERENCIA</th>
          <th style="background:#000; color:#fff; padding:10px; text-align:left;">DETALLES / COLORES</th>
          <th style="background:#000; color:#fff; padding:10px; text-align:center;">CANT.</th>
          <th style="background:#000; color:#fff; padding:10px; text-align:right;">V. UNITARIO</th>
          <th style="background:#000; color:#fff; padding:10px; text-align:right;">V. TOTAL</th>
        </tr>
      </thead>
      <tbody>
        ${rowsHtml}
      </tbody>
    </table>

    <div style="margin-top:14px; text-align:right; font-size:16px; font-weight:900; color:#000;">
      TOTAL: ${fmtCOP(totalGeneral)} COP
    </div>

    <div style="margin-top:18px; padding:12px; border:1px solid #ddd; background:#fff; color:#000; border-radius:8px;">
      <strong>Observaciones:</strong><br>
      ${observaciones ? String(observaciones).replaceAll("\n","<br>") : "Sin observaciones"}
    </div>
  </div>`;
}

function ensurePDFContainer() {
  let el = document.getElementById("pdfContainer");
  if (!el) {
    el = document.createElement("div");
    el.id = "pdfContainer";
    document.body.appendChild(el);
  }
  // IMPORTANTÍSIMO: no display:none
  el.style.position = "fixed";
  el.style.left = "-9999px";
  el.style.top = "0";
  el.style.width = "800px";
  el.style.background = "#fff";
  el.style.opacity = "1";
  el.style.zIndex = "0";
  return el;
}

async function exportarPDFCliente() {
  if (!itemsCotizacion || itemsCotizacion.length === 0) {
    alert("No hay productos en el pedido.");
    return;
  }

  const clienteNombre = document.getElementById("inpCliente")?.value || "CLIENTE VALIOSO";
  const fechaStr = new Date().toLocaleDateString("es-CO");
  const observaciones = document.getElementById("inpNotas")?.value || "";

  const rowsHtml = itemsCotizacion.map(it => `
    <tr>
      <td style="padding:10px; border-bottom:1px solid #ddd; font-weight:700;">${it.referencia}</td>
      <td style="padding:10px; border-bottom:1px solid #ddd;">
        Talla: ${it.talla || "-"}<br>
        ${it.colorCamiseta ? `CAMISETA: <strong>${it.colorCamiseta}</strong><br>` : ``}
        ${it.colorBermuda && it.colorBermuda !== "No aplica" ? `BERMUDA/JOGGER: <strong>${it.colorBermuda}</strong>` : ``}
      </td>
      <td style="padding:10px; border-bottom:1px solid #ddd; text-align:center;">${it.cantidad}</td>
      <td style="padding:10px; border-bottom:1px solid #ddd; text-align:right;">${fmtCOP(it.unit)}</td>
      <td style="padding:10px; border-bottom:1px solid #ddd; text-align:right;">${fmtCOP(it.total)}</td>
    </tr>
  `).join("");

  const totalGeneral = itemsCotizacion.reduce((acc, it) => acc + Number(it.total || 0), 0);

  const pdfEl = ensurePDFContainer();
  pdfEl.innerHTML = buildPDFHtml({ clienteNombre, fechaStr, rowsHtml, totalGeneral, observaciones });

  // ✅ espera 1 frame para que el DOM pinte antes de capturar
  await new Promise(r => requestAnimationFrame(r));

  if (typeof html2pdf === "undefined") {
    alert("No está cargada la librería html2pdf.");
    return;
  }

  await html2pdf().set({
    margin: 10,
    filename: `cotizacion_${Date.now()}.pdf`,
    image: { type: "jpeg", quality: 0.98 },
    html2canvas: { scale: 2, backgroundColor: "#ffffff" },
    jsPDF: { unit: "mm", format: "a4", orientation: "portrait" }
  }).from(pdfEl).save();
}


