SOLUCIÓN DEFINITIVA: PDF con jsPDF (sin html2canvas)
1) Agrega estas librerías en tu HTML (ANTES de tu JS)
<script src="https://cdn.jsdelivr.net/npm/jspdf@2.5.1/dist/jspdf.umd.min.js"></script>
<script src="https://cdn.jsdelivr.net/npm/jspdf-autotable@3.5.31/dist/jspdf.plugin.autotable.min.js"></script>

2) Función de exportar PDF (tabla + total + observaciones)

Pega esto en tu JS:

function fmtCOP(n){
  return "$ " + Math.round(Number(n||0)).toLocaleString("es-CO");
}

function exportarPDFCliente_jsPDF(){
  // 1) Validaciones
  if(!window.itemsCotizacion || window.itemsCotizacion.length === 0){
    alert("No hay productos en el pedido para exportar.");
    return;
  }

  const { jsPDF } = window.jspdf || {};
  if(!jsPDF){
    alert("No se cargó jsPDF. Revisa los scripts CDN.");
    return;
  }

  // 2) Datos encabezado (ajusta IDs si los tuyos son diferentes)
  const clienteNombre = document.getElementById("inpCliente")?.value || "CLIENTE VALIOSO";
  const observaciones = document.getElementById("inpNotas")?.value || "";
  const fechaStr = new Date().toLocaleDateString("es-CO");

  // 3) Construye filas (con colores discriminados)
  const body = window.itemsCotizacion.map(it => {
    const detalle =
      `Talla: ${it.talla || "-"}\n` +
      (it.colorCamiseta ? `Camiseta: ${it.colorCamiseta}\n` : "") +
      (it.colorBermuda && it.colorBermuda !== "No aplica" ? `Bermuda/Jogger: ${it.colorBermuda}` : "");

    return [
      it.referencia || "-",
      detalle.trim(),
      String(it.cantidad || 1),
      fmtCOP(it.unit || 0),
      fmtCOP(it.total || 0),
    ];
  });

  const totalGeneral = window.itemsCotizacion.reduce((acc, it) => acc + Number(it.total||0), 0);

  // 4) PDF
  const doc = new jsPDF("p","mm","a4");

  // Encabezado
  doc.setFont("helvetica","bold");
  doc.setFontSize(12);
  doc.text(`CLIENTE: ${clienteNombre}`, 14, 14);
  doc.setFont("helvetica","normal");
  doc.setFontSize(11);
  doc.text(`FECHA: ${fechaStr}`, 14, 20);

  // Tabla
  doc.autoTable({
    startY: 28,
    head: [["REFERENCIA", "DETALLES / COLORES", "CANT.", "V. UNITARIO", "V. TOTAL"]],
    body,
    styles: { font: "helvetica", fontSize: 9, cellPadding: 3, valign: "top" },
    headStyles: { fillColor: [0,0,0], textColor: [255,255,255], fontStyle: "bold" },
    columnStyles: {
      0: { cellWidth: 55 },
      1: { cellWidth: 70 },
      2: { halign: "center", cellWidth: 12 },
      3: { halign: "right", cellWidth: 25 },
      4: { halign: "right", cellWidth: 25 },
    },
    theme: "grid",
  });

  // Total (solo texto negro en negrilla)
  const y = doc.lastAutoTable.finalY + 10;
  doc.setFont("helvetica","bold");
  doc.setFontSize(13);
  doc.text(`TOTAL: ${fmtCOP(totalGeneral)} COP`, 200, y, { align: "right" });

  // Observaciones (fondo blanco, texto negro)
  doc.setFont("helvetica","bold");
  doc.setFontSize(11);
  doc.text("Observaciones:", 14, y + 12);
  doc.setFont("helvetica","normal");
  doc.setFontSize(10);

  const obs = (observaciones || "Sin observaciones").toString();
  const lines = doc.splitTextToSize(obs, 180);
  doc.text(lines, 14, y + 18);

  // Descargar
  doc.save(`cotizacion_${Date.now()}.pdf`);
}

3) Conecta tu botón “EXPORTAR PDF PARA CLIENTE”

Asegúrate que tenga un id fijo, por ejemplo:

<button id="btnExportPDF" type="button">EXPORTAR PDF PARA CLIENTE</button>


Y en JS:

document.addEventListener("click", (e) => {
  const btn = e.target.closest("#btnExportPDF");
  if(!btn) return;
  exportarPDFCliente_jsPDF();
});

✅ Por qué esto SÍ te lo arregla

No usa html2canvas → no hay “captura en blanco”

No se rompe por PNG corruptos, fondos, z-index, opacity

Siempre exporta la tabla con datos directo desde itemsCotizacion

Mini-check (muy importante)

Para que no salga vacío:

window.itemsCotizacion = itemsCotizacion;

