(Usa los IDs reales que ya tienes; lo importante es el wrapper wrapColorInferior.)

2) Función para detectar “conjunto” por referencia

Pega esto en tu JS:

function esConjunto(ref){
  ref = (ref || "").toLowerCase();
  return ref.includes("conjunto") || ref.includes("jogger") || ref.includes("bermuda") || ref.includes("joker");
}


Si tus referencias de conjunto tienen otra palabra clave, me dices y lo ajusto.

3) Mostrar / ocultar automáticamente el color inferior

Pega esto:

const selCategoria = document.getElementById("selCategoria");
const selReferencia = document.getElementById("selReferencia");

const wrapColorInferior = document.getElementById("wrapColorInferior");
const selColorInferior = document.getElementById("selColorInferior");

function setNoAplicaColorInferior(){
  // deja el campo en “No aplica” para que NO se cuele en PDF/cotización
  selColorInferior.innerHTML = `<option value="No aplica">No aplica</option>`;
  selColorInferior.value = "No aplica";
}

function actualizarColorInferiorUI(){
  const categoria = (selCategoria?.value || "").toLowerCase();
  const ref = selReferencia?.value || "";
  const mostrar = (categoria === "niño" || categoria === "nino") && esConjunto(ref);

  if(mostrar){
    wrapColorInferior.style.display = "";
    // vuelve a cargar tus colores reales
    setOptions(selColorInferior, COLORES_BERMUDA, "Color bermuda/jogger...");
  } else {
    wrapColorInferior.style.display = "none";
    setNoAplicaColorInferior();
  }
}

// cuando cambie referencia o categoría
selCategoria?.addEventListener("change", () => {
  actualizarColorInferiorUI();
  recalcular?.();
});

selReferencia?.addEventListener("change", () => {
  actualizarColorInferiorUI();
  recalcular?.();
});

// al cargar
actualizarColorInferiorUI();

