  "Azul Oscuro",
  "Lila",
  "Verde Antioquia",
  "Camel",
  "Fucsia",
  "Fantasía",
  "Verde Oliva",
  "Café"
];

2️⃣ Función para cargar el select incluyendo “No aplica”

Usa esta función para TODOS tus desplegables de colores:

function setOptions(selectEl, options, placeholder = "Seleccione...") {
  if (!selectEl) return;

  selectEl.innerHTML = "";

  // ✅ Opción No aplica
  const optNo = document.createElement("option");
  optNo.value = "No aplica";
  optNo.textContent = "No aplica";
  selectEl.appendChild(optNo);

  // Opciones reales
  options.forEach(opt => {
    const o = document.createElement("option");
    o.value = opt;
    o.textContent = opt;
    selectEl.appendChild(o);
  });

  // Por defecto: No aplica
  selectEl.value = "No aplica";
}

3️⃣ Aplica la función al cargar el formulario

Por ejemplo:

const selColorInferior = document.getElementById("selColorInferior");
setOptions(selColorInferior, COLORES_BERMUDA);


Si quieres hacerlo también en camisetas:

const COLORES_CAMISETA = [
  "Blanco",
  "Negro",
  "Arena",
