import React, { useState, useMemo, useRef, useEffect } from 'react';
import * as XLSX from 'xlsx';
import { QuoteInputs, QuoteResults, ProductReference, QuoteItem } from './types';
import { 
  PRODUCT_REFERENCES_INITIAL, 
  TALLAS_NINO, 
  TALLAS_ADULTO, 
  COLORES_CAMISETA,
  COLORES_BERMUDA,
  COSTO_CM2, 
  COSTO_PLANCHADO,
  COSTO_EMPAQUE,
  GANANCIA_NINO,
  GANANCIA_ADULTO
} from './constants';
import { 
  FileUp,
  Download,
  MessageSquare,
  User,
  Plus,
