    doc.setFontSize(8);
    doc.setTextColor(180, 180, 180);
    doc.text("Furia Rock Kids - Pasión por el diseño infantil con alma rockera.", pageWidth / 2, 200, { align: "center" });

    doc.save(`Cotizacion_FuriaRock_${Date.now()}.pdf`);
